      ]
    }
  },
  async created () {
    const {data} = await axios.get('http://server.chokospace.kro.kr:3901/api/chokomemo/memo')
    this.name = data.name
  },
  methods: {
    increaseReportCount(i){
      this.products[i].reportCount++;
    }
  },
  components: {
  }
}
</script>

